# Secret key for HMAC signing - in production, load from secure config/env
_SIGNING_KEY = os.environ.get("PREFS_SIGNING_KEY", "change-this-to-a-secure-random-key").encode()


class UserPreference:
    """Custom user preference object that can be safely serialized."""
    
    def __init__(self, key: str, value: Any, category: str = "general",
                 created_at: Optional[str] = None, metadata: Optional[dict] = None):
        self.key = key
        self.value = value
        self.category = category
        self.created_at = created_at or datetime.now().isoformat()
        self.metadata = metadata or {}
    
    def to_dict(self) -> dict:
        return {
            "__type__": "UserPreference",
            "key": self.key,
            "value": self.value,
            "category": self.category,
            "created_at": self.created_at,
            "metadata": self.metadata,
        }
    
    @classmethod
    def from_dict(cls, data: dict) -> "UserPreference":
        return cls(
            key=data["key"],
            value=data["value"],
            category=data.get("category", "general"),
            created_at=data.get("created_at"),
            metadata=data.get("metadata", {}),
        )
    
    def __eq__(self, other):
        if not isinstance(other, UserPreference):
            return False
        return (self.key == other.key and self.value == other.value and
                self.category == other.category and self.created_at == other.created_at and
                self.metadata == other.metadata)
    
    def __repr__(self):
        return f"UserPreference(key={self.key!r}, value={self.value!r}, category={self.category!r})"


