# Registry of allowed types for deserialization (whitelist approach)
_SAFE_TYPE_REGISTRY = {
    "UserPreference": UserPreference,
    "ThemeConfig": ThemeConfig,
}


def register_safe_type(type_name: str, cls: type):
    """Register a custom type as safe for deserialization.
    
    Only registered types can be deserialized, preventing arbitrary code execution.
    """
    if not hasattr(cls, 'from_dict') or not hasattr(cls, 'to_dict'):
        raise ValueError(f"Class {cls.__name__} must implement 'to_dict' and 'from_dict' methods")
    _SAFE_TYPE_REGISTRY[type_name] = cls


class SafePreferenceEncoder(json.JSONEncoder):
    """JSON encoder that handles custom preference objects and Python types."""
    
    def default(self, obj):
        # Handle registered custom types
        if hasattr(obj, 'to_dict'):
            type_name = type(obj).__name__
            if type_name in _SAFE_TYPE_REGISTRY:
                return obj.to_dict()
        
        # Handle datetime objects
        if isinstance(obj, datetime):
            return {"__type__": "datetime", "value": obj.isoformat()}
        if isinstance(obj, date):
            return {"__type__": "date", "value": obj.isoformat()}
        
        # Handle sets (convert to sorted list for deterministic output)
        if isinstance(obj, set):
            return {"__type__": "set", "value": sorted(obj, key=str)}
        
        # Handle tuples
        if isinstance(obj, tuple):
            return {"__type__": "tuple", "value": list(obj)}
        
        # Handle bytes
        if isinstance(obj, bytes):
            return {"__type__": "bytes", "value": obj.hex()}
        
        # Handle Path objects
        if isinstance(obj, Path):
            return {"__type__": "Path", "value": str(obj)}
        
        return super().default(obj)


def _safe_object_hook(data: dict) -> Any:
    """Decode JSON objects back to Python types using a strict whitelist."""
    if "__type__" not in data:
        return data
    
    type_name = data["__type__"]
    
    # Check whitelist of allowed custom types
    if type_name in _SAFE_TYPE_REGISTRY:
        cls = _SAFE_TYPE_REGISTRY[type_name]
        return cls.from_dict(data)
    
    # Handle built-in Python types
    if type_name == "datetime":
        return datetime.fromisoformat(data["value"])
    if type_name == "date":
        return date.fromisoformat(data["value"])
    if type_name == "set":
        return set(data["value"])
    if type_name == "tuple":
        return tuple(data["value"])
    if type_name == "bytes":
        return bytes.fromhex(data["value"])
    if type_name == "Path":
        return Path(data["value"])
    
    # Unknown type - refuse to deserialize (prevent insecure deserialization)
    raise ValueError(f"Refusing to deserialize unknown type: {type_name!r}. "
                     f"Allowed types: {list(_SAFE_TYPE_REGISTRY.keys()) + ['datetime', 'date', 'set', 'tuple', 'bytes', 'Path']}")


def _compute_hmac(data: bytes) -> str:
    """Compute HMAC-SHA256 signature for data integrity verification."""
    return hmac.new(_SIGNING_KEY, data, hashlib.sha256).hexdigest()


def _verify_hmac(data: bytes, signature: str) -> bool:
    """Verify HMAC signature using constant-time comparison."""
    expected = hmac.new(_SIGNING_KEY, data, hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected, signature)


def _validate_preferences_structure(prefs: Any, max_depth: int = 20, _current_depth: int = 0) -> None:
    """Validate that preferences don't exceed reasonable size/depth limits."""
    if _current_depth > max_depth:
        raise ValueError(f"Preferences nesting depth exceeds maximum of {max_depth}")
    
    if isinstance(prefs, dict):
        if len(prefs) > 10000:
            raise ValueError("Preferences dictionary exceeds maximum of 10000 keys")
        for key, value in prefs.items():
            if not isinstance(key, str):
                raise ValueError(f"Dictionary keys must be strings, got {type(key).__name__}")
            _validate_preferences_structure(value, max_depth, _current_depth + 1)
    elif isinstance(prefs, (list, tuple, set)):
        if len(prefs) > 100000:
            raise ValueError("Preferences collection exceeds maximum of 100000 items")
        for item in prefs:
            _validate_preferences_structure(item, max_depth, _current_depth + 1)


def save_preferences(preferences: dict, filepath: str, pretty: bool = False) -> None:
    """Save user preferences to a signed JSON file.
    
    Uses JSON for safe serialization (no arbitrary code execution on load).
    The file is signed with HMAC to detect tampering.
    Writes atomically to prevent corruption.
    
    Args:
        preferences: Dictionary of user preferences (can contain nested dicts,
                     lists, custom objects like UserPreference and ThemeConfig).
        filepath: Path to the preferences file.
        pretty: If True, format JSON for readability.
    
    Raises:
        ValueError: If preferences structure is invalid.
        TypeError: If preferences contain unserializable types.
    """
    if not isinstance(preferences, dict):
        raise TypeError("Preferences must be a dictionary")
    
    _validate_preferences_structure(preferences)
    
    # Serialize to JSON using our safe encoder
    json_kwargs = {
        "cls": SafePreferenceEncoder,
        "ensure_ascii": False,
        "sort_keys": True,  # Deterministic output
    }
    if pretty:
        json_kwargs["indent"] = 2
    
    json_data = json.dumps(preferences, **json_kwargs).encode("utf-8")
    
    # Compute HMAC signature
    signature = _compute_hmac(json_data)
    
    # Create the signed file content
    file_content = json.dumps({
        "version": 1,
        "signature": signature,
        "data": json.loads(json_data.decode("utf-8")),
    }, cls=SafePreferenceEncoder, ensure_ascii=False, sort_keys=True,
       indent=2 if pretty else None).encode("utf-8")
    
    # Atomic write: write to temp file then rename
    dir_path = os.path.dirname(os.path.abspath(filepath))
    os.makedirs(dir_path, exist_ok=True)
    
    fd, tmp_path = tempfile.mkstemp(dir=dir_path, suffix=".tmp")
    try:
        with os.fdopen(fd, "wb") as f:
            f.write(file_content)
            f.flush()
            os.fsync(f.fileno())
        os.replace(tmp_path, filepath)
    except Exception:
        # Clean up temp file on failure
        try:
            os.unlink(tmp_path)
        except OSError:
            pass
        raise


def load_preferences(filepath: str) -> dict:
    """Load user preferences from a signed JSON file.
    
    Verifies HMAC signature to detect tampering before deserializing.
    Uses a strict whitelist of allowed types to prevent insecure deserialization.
    
    Args:
        filepath: Path to the preferences file.
    
    Returns:
        Dictionary of user preferences with custom objects restored.
    
    Raises:
        FileNotFoundError: If the preferences file doesn't exist.
        ValueError: If the file has been tampered with or contains invalid data.
    """
    with open(filepath, "rb") as f:
        raw_content = f.read()
    
    # First pass: parse the envelope without custom object hooks
    try:
        envelope = json.loads(raw_content.decode("utf-8"))
    except (json.JSONDecodeError, UnicodeDecodeError) as e:
        raise ValueError(f"Invalid preferences file format: {e}")
    
    if not isinstance(envelope, dict):
        raise ValueError("Invalid preferences file structure")
    
    version = envelope.get("version")
    if version != 1:
        raise ValueError(f"Unsupported preferences file version: {version}")
    
    stored_signature = envelope.get("signature")
    if not isinstance(stored_signature, str):
        raise ValueError("Missing or invalid signature in preferences file")
    
    data = envelope.get("data")
    if data is None:
        raise ValueError("Missing data in preferences file")
    
    # Re-serialize the data portion to verify signature
    # Must match the exact serialization used during save
    json_data = json.dumps(data, cls=SafePreferenceEncoder, ensure_ascii=False,
                           sort_keys=True).encode("utf-8")
    
    # Verify HMAC signature (constant-time comparison)
    if not _verify_hmac(json_data, stored_signature):
        raise ValueError("Preferences file signature verification failed - "
                         "file may have been tampered with")
    
    # Second pass: deserialize with our safe object hook (whitelist-based)
    # Re-parse the data through our safe decoder
    preferences = json.loads(json_data.decode("utf-8"), object_hook=_safe_object_hook)
    
    if not isinstance(preferences, dict):
        raise ValueError("Preferences root must be a dictionary")
    
    return preferences


